    res = [...res, x]; // каждый раз копируем весь res → O(len)
  }
  return res; // Итого O(n^2)
}

function goodAppend(items) {
  const res = [];
  for (const x of items) res.push(x); // амортизированно O(1)
  return res; // Итого O(n)
}"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Два вызова map/filter подряд — всё ещё O(n). Объединение в один проход снижает константы, но не меняет O-нотацию."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ранний выход улучшает лучший/средний случай, но асимптотика по худшему остаётся O(n)."}]}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Интуиция: удвоили количество данных — время примерно удвоилось. Это и есть линейность."}]}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"O(n²) — это квадратичная временная сложность: время работы алгоритма растёт пропорционально квадрату размера входа n. Типичный источник — вложенные циклы по одному и тому же набору данных, дающие примерно n × n элементарных операций."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Развернутый ответ"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Определение и суть"}]},{"type":"paragraph","content":[{"type":"text","text":"Запись O(n²) означает, что число элементарных операций алгоритма для входа размера n можно оценить сверху выражением вида c·n² + a·n + b, где константы c, a, b не зависят от n. В нотации O-символики учитывается только главный (наибыстрее растущий) член — n², а константы и младшие члены отбрасываются."}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Интуитивно: если вы удвоите n, время приблизительно вырастет в 4 раза; если увеличите n в 10 раз — примерно в 100 раз."}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Когда возникает O(n²)"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Два вложенных цикла по одному и тому же массиву/списку."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Перебор всех пар элементов набора (количество пар — n(n−1)/2)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Некоторые сортировки в худшем случае (например, пузырьковая сортировка, простой выбор, вставки — худший случай)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Операции над матрицами n×n, где требуется посетить каждый элемент (например, сравнение каждой строки с каждой строкой)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Примеры кода (JavaScript)"}]},{"type":"paragraph","content":[{"type":"text","text":"1) Подсчёт числа пар — классический O(n²):"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"function countPairs(arr) {
  let count = 0;
  for (let i = 0; i < arr.length; i++) {
    for (let j = i + 1; j < arr.length; j++) {
      count++; // элементарная операция
    }
  }
  return count; // ~ n(n-1)/2 => O(n^2)
}
"}]},{"type":"paragraph","content":[{"type":"text","text":"2) Пузырьковая сортировка — худший случай O(n²), лучший — O(n) за счёт раннего выхода:"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"function bubbleSort(a) {
  const n = a.length;
  for (let i = 0; i < n - 1; i++) {
    let swapped = false;
    for (let j = 0; j < n - 1 - i; j++) {
      if (a[j] > a[j + 1]) {
        [a[j], a[j + 1]] = [a[j + 1], a[j]];
        swapped = true;
      }
    }
    if (!swapped) break; // массив уже отсортирован => линейный пробег
  }
  return a;
}
"}]},{"type":"paragraph","content":[{"type":"text","text":"3) Сравнение O(n²) и улучшенной версии: задача Two Sum (найти пару с заданной суммой)."}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"// Наивно: O(n^2)
function twoSumBrute(nums, target) {
  for (let i = 0; i < nums.length; i++) {
    for (let j = i + 1; j < nums.length; j++) {
      if (nums[i] + nums[j] === target) return [i, j];
    }
  }
  return null;
}

// Эффективно с Map: O(n) по времени, O(n) по памяти
function twoSumHash(nums, target) {
  const map = new Map(); // значение -> индекс
  for (let i = 0; i < nums.length; i++) {
    const need = target - nums[i];
    if (map.has(need)) return [map.get(need), i];
    map.set(nums[i], i);
  }
  return null;
}
"}]},{"type":"paragraph","content":[{"type":"text","text":"4) Разные размеры циклов: O(n·m). Если m пропорционален n, это вырождается в O(n²):"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"function processGrid(n, m) {
  let ops = 0;
  for (let i = 0; i < n; i++) {
    for (let j = 0; j < m; j++) {
      ops++;
    }
  }
  return ops; // O(n*m); если m ≈ n, то O(n^2)
}
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Подсчёт операций и интуиция"}]},{"type":"paragraph","content":[{"type":"text","text":"Часто встречается треугольный перебор: i идёт от 0 до n−1, j идёт от i+1 до n−1. Тогда число итераций равно 1 + 2 + ... + (n−1) = n(n−1)/2, что асимптотически ведёт к O(n²). Это объясняет, почему сравнение «каждого с каждым» быстро становится дорогим."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как это ощущается на практике"}]},{"type":"table","content":[{"type":"tableRow","content":[{"type":"tableHeader","content":[{"type":"paragraph","content":[{"type":"text","text":"n"}]}]},{"type":"tableHeader","content":[{"type":"paragraph","content":[{"type":"text","text":"Операции ~ n²"}]}]},{"type":"tableHeader","content":[{"type":"paragraph","content":[{"type":"text","text":"Рост vs n=1"}]}]}]},{"type":"tableRow","content":[{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"10"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"100"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"×100"}]}]}]},{"type":"tableRow","content":[{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"100"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"10 000"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"×10 000"}]}]}]},{"type":"tableRow","content":[{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"1 000"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"1 000 000"}]}]},{"type":"tableCell","content":[{"type":"paragraph","content":[{"type":"text","text":"×1 000 000"}]}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Когда O(n²) приемлемо"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Малые n (десятки или сотни), однократный запуск, нет жёстких SLO."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Прототипирование, где важна скорость разработки, а не идеальная асимптотика."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как улучшить с O(n²) до быстрее"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Использовать хеш-структуры (Map/Set) для проверки принадлежности или поиска пары за O(1) в среднем."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Отсортировать и применить двухуказатели или бинпоиск: обычно O(n log n) вместо O(n²)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Кэширование/мемоизация результатов подзадач, чтобы не пересчитывать одинаковое."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ранняя остановка и отсечение случаев, где дальнейший перебор бессмыслен."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Переформулировать задачу (математика/геометрия/структуры данных) так, чтобы не перебирать «каждого с каждым»."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Важные нюансы на собеседовании"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"O(n²) — это верхняя оценка (upper bound). Если хотите подчеркнуть «точную» асимптотику, используйте Θ(n²)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Вложенные циклы не всегда означают O(n²): если внутренний цикл в сумме выполняется константное число раз, сложность может быть O(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"O(n·m) — не то же самое, что O(n²). Но если m ≈ n, это становится квадратичным."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: O(n²) по времени не означает O(n²) по памяти. Хранение всех пар — это уже O(n²) памяти; одиночные вложенные циклы могут использовать O(1) памяти."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Итог"}]},{"type":"paragraph","content":[{"type":"text","text":"O(n²) — это классическая характеристика алгоритмов, перебирающих все пары элементов. Она быстро становится непрактичной при росте n, поэтому на собеседованиях ожидают, что вы либо аргументируете приемлемость квадратичной сложности для данного n, либо предложите стратегию снижения до O(n log n) или O(n) с помощью сортировки, хеш-структур и других приёмов."}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Что означает «наихудший случай» (worst case)?"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Наихудший случай — это оценка верхней границы ресурсов (времени и/или памяти), которые алгоритм или операция могут потребовать при наиболее неблагоприятных входных данных. Обычно выражается в нотации O(·) и гарантирует, что при любом вводе сложность не превысит указанную."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Отвечает на вопрос: «Как плохо может быть?»"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дает гарантии: время/память не хуже указанной оценки."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Контрастирует с «средним» и «лучшими» случаями."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Развернутый ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"В анализе алгоритмов рассматривают три сценария: лучший, средний и наихудший случаи. Наихудший случай — это сценарий входных данных, при котором алгоритм работает максимально долго или потребляет больше всего памяти. Такая оценка важна, потому что дает верхнюю границу сложности, то есть строгую гарантию: «хуже не будет»."}]},{"type":"orderedList","attrs":{"order":1},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Лучший случай: минимальные затраты. Пример — поиск элемента, который стоит на первом месте: O(1)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Средний случай: усреднение по распределению входов. Пример — поиск случайного элемента в несортированном массиве: ≈O(n/2) → O(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Наихудший случай: максимальные затраты. Пример — поиск элемента, которого нет в массиве: O(n)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Зачем это нужно на собеседовании"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Показывает, что вы умеете мыслить о гарантированных границах времени/памяти, а не только о «средней» производительности."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Позволяет сравнивать структуры данных и алгоритмы в условиях пиковых нагрузок (латентность API, рост трафика, атакующие/адверсариальные входы)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Помогает объяснить выбор: «Почему здесь подойдет хеш-таблица, а не сбалансированное дерево?» — с учетом наихудшей сложности."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Типовые примеры «наихудшего случая»"}]},{"type":"orderedList","attrs":{"order":1},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Линейный поиск в несортированном массиве: O(n) — если элемента нет (пройти весь массив)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Быстрая сортировка: O(n^2) — если каждый раз выбирать худший опорный элемент (например, уже отсортированный массив и плохой выбор пивота)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Поиск в хеш-таблице: O(n) — при множественных коллизиях (все ключи в одном бакете)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Регулярные выражения с возвратом (backtracking): экспоненциальный рост времени на определенных строках (катастрофический бэктрекинг) — важно при фильтрации пользовательского ввода."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Связь с пространственной сложностью"}]},{"type":"paragraph","content":[{"type":"text","text":"Наихудший случай применяется и к памяти: например, глубина рекурсии при неблагоприятном вводе может потребовать O(n) стека, тогда как в среднем — меньше. В системах с ограниченной памятью (браузер на мобильном, безлимитного хранилища нет) это критично."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как рассуждать о наихудшем случае"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Определите операцию, которую считаете примитивом: сравнение, доступ по индексу, вставка и т. п."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Найдите входные данные, вынуждающие выполнить максимум таких операций (например, отсутствующий элемент, отсортированный ввод для плохого пивота и т. д.)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Оцените асимптотику по n (размер входа) и/или по другим параметрам (число ключей, глубина, ширина графа)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример кода: линейный поиск и его наихудший случай"}]},{"type":"paragraph","content":[{"type":"text","text":"В несортированном массиве линейный поиск в наихудшем случае требует просмотреть все элементы: O(n). Лучший случай — элемент найден на первом месте: O(1). Средний — примерно половина прохода: O(n)."}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"// Линейный поиск: возвращает индекс или -1, если не найден
function linearSearch(arr, target) {
  for (let i = 0; i < arr.length; i++) {
    if (arr[i] === target) return i; // найден — ранний выход
  }
  return -1; // наихудший случай — прошли весь массив и не нашли
}

// Демонстрация: лучший, средний и наихудший случаи
const arr = Array.from({ length: 100000 }, (_, i) => i); // [0, 1, 2, ...]

console.time('best');
linearSearch(arr, 0); // лучший случай: элемент в начале → O(1)
console.timeEnd('best');

console.time('average');
linearSearch(arr, Math.floor(arr.length / 2)); // средний случай → ≈O(n)
console.timeEnd('average');

console.time('worst');
linearSearch(arr, -1); // наихудший случай: элемента нет → O(n)
console.timeEnd('worst');"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Практические советы для интервью"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сначала проговорите, что оцениваете верхнюю границу: «В наихудшем случае время — O(n), память — O(1)»."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Кратко сравните с альтернативой (например, хеш-таблица против массива) и объясните, что поменяется в наихудшем случае."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Озвучьте предположения: распределение входов, возможность предобработки (сортировки), ограничения по памяти/латентности."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Если есть адверсариальные входы (пользовательский ввод, атаки), ориентируйтесь на гарантии наихудшего случая."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Короткий чек-лист ответа на собеседовании"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дать определение: верхняя граница времени/памяти на худшем вводе."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Назвать асимптотику: O(·) по времени и по памяти."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сравнить с лучшим/средним случаями одним предложением."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Привести мини-пример (поиск, сортировка) и объяснить, почему это худший ввод."}]}]}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Объем памяти алгоритма измеряется как пространственная сложность S(n) — функция от размера входа n. Обычно указывают асимптотическую оценку в O-нотации для пикового объема дополнительной (auxiliary) памяти, которую алгоритм одновременно использует: переменные, временные структуры данных и рекурсивный стек. При необходимости различают общую память (вход + выход + дополнительно) и уточняют, для какого случая (худший, средний, амортизированный) дана оценка."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Развернутый ответ"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Что именно измеряем"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Общая память: S_total(n) = S_input(n) + S_output(n) + S_aux(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дополнительная (auxiliary) память: все, что алгоритм выделяет сверх хранения входа и результата. На собеседованиях обычно спрашивают именно ее."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Пиковый объем: "},{"type":"text","text":"максимальный Одновременный","marks":[]},{"type":"text","text":" объем памяти за все время работы, а не суммарно выделенный/освобожденный."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Случай: худший (worst-case), средний (average-case) или амортизированный. Не забудьте уточнить это в ответе."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Модель и единицы измерения"}]},{"type":"paragraph","content":[{"type":"text","text":"Обычно используют модель RAM/word-RAM: считаем память в машинах словах (или байтах), а затем упрощаем до функции от n и берем асимптотику."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Скалярные переменные: O(1)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Массив длины k: O(k). Матрица n×m: O(n·m)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Хеш-таблица/словарь с k элементами: O(k)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Рекурсивный вызов глубины h: O(h) дополнительной памяти под стек."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как оценивать на практике (алгоритм действий)"}]},{"type":"orderedList","attrs":{"start":1},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Определите, что считать: общую или дополнительную память; пиковую или суммарно выделенную."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Разбейте алгоритм на фазы и перечислите одновременно живые структуры данных."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Учтите стек рекурсии или внутренний стек/очереди при обходах."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сложите размеры (в словах/байтах) и выразите как S(n); упростите до O(·), Θ(·) или Ω(·)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Уточните случай (худший/средний/амортизированный) и зависимости от дополнительных параметров (k — число уникальных, V/E — размер графа и т. п.)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"При необходимости дайте точную оценку в байтах для конкретной реализации (например, 4 байта на 32-битное целое)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Типичные составляющие памяти"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Хранение входных данных (часто не включают в auxiliary)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память под выход (часто считают отдельно; например, возврат нового массива длины k — O(k))."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Временные структуры: массивы, хеш-таблицы, очереди/стеки, буферы."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Стек рекурсии или глубина итеративного стека при обходах."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Накладные расходы структур (заголовки объектов, указатели) — учитываются при точных подсчетах, но опускаются в асимптотике."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Короткие примеры оценок"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Поиск максимума в массиве одним проходом: O(1) auxiliary."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Подсчет частот с помощью Map по n элементам: O(k), где k — число уникальных значений (k ≤ n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"BFS в графе: очередь O(V), массив visited O(V) → auxiliary O(V)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Merge sort: O(n) дополнительной памяти; Quick sort: O(log n) стек в среднем, O(n) в худшем."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"ДП с таблицей n×m: O(nm), но иногда можно оптимизировать до O(min(n, m)) по памяти, храня только нужную строку/столбец."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Примеры кода"}]},{"type":"paragraph","content":[{"type":"text","text":"Два подхода к задаче two-sum показывают различия в дополнительной памяти."}]},{"type":"codeBlock","content":[{"type":"text","text":"// Пример 1: поиск пары с суммой target — разные профили памяти
// Вариант A: хеш-таблица — O(n) дополнительной памяти
function twoSumHash(nums, target) {
  const map = new Map(); // до n записей ⇒ O(n)
  for (let i = 0; i < nums.length; i++) {
    const need = target - nums[i];
    if (map.has(need)) return [map.get(need), i];
    map.set(nums[i], i);
  }
  return null;
}

// Вариант B: два указателя после сортировки — O(1) доп. памяти (если сортировка in-place)
// Важные оговорки:
// - Если сортировка — быстрая (in-place), стек рекурсии ≈ O(log n) в среднем.
// - Если сортировка — стабильная merge-sort, доп. память может быть O(n).
function twoSumTwoPointers(nums, target) {
  nums.sort((a, b) => a - b); // потенциально O(1) auxiliary + O(log n) стек, зависит от реализации
  let l = 0, r = nums.length - 1; // несколько скаляров ⇒ O(1)
  while (l < r) {
    const sum = nums[l] + nums[r]; // O(1)
    if (sum === target) return [nums[l], nums[r]]; // возвращаем результат (выходная память)
    if (sum < target) l++; else r--;
  }
  return null;
}
"}]},{"type":"paragraph","content":[{"type":"text","text":"Рекурсия vs. итерация: и там, и там O(h), где h — максимальная глубина."}]},{"type":"codeBlock","content":[{"type":"text","text":"// Пример 2: обход дерева — память из-за глубины
// Рекурсивный DFS: O(h) из-за стека вызовов
function dfsRec(node) {
  if (!node) return;          // O(1)
  // ... обработка node
  dfsRec(node.left);          // глубина растет ⇒ память O(h)
  dfsRec(node.right);
}

// Итеративный DFS со своим стеком: тоже O(h), но стек контролируем мы
function dfsIter(root) {
  if (!root) return;
  const stack = [root]; // в пике до h элементов ⇒ O(h)
  while (stack.length) {
    const node = stack.pop(); // O(1)
    // ... обработка node
    if (node.right) stack.push(node.right);
    if (node.left) stack.push(node.left);
  }
}
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Частые ошибки"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Считать суммарно выделенную память вместо пикового одновременного использования."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Забывать про стек рекурсии (даже если структуры данных явно не создаются)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не уточнять, включается ли вход и выход в оценку (auxiliary vs total)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Путать in-place операции с теми, что создают копии (например, методы, возвращающие новый массив)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Игнорировать параметры, кроме n (например, k — число уникальных значений, диапазон значений, V и E в графах)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Давать среднюю оценку там, где важно худшее поведение."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Итог"}]},{"type":"paragraph","content":[{"type":"text","text":"Чтобы измерить объем памяти алгоритма, перечислите одновременно живые объекты, посчитайте их суммарный размер, выразите его как функцию от параметров входа, а затем приведите асимптотическую оценку (обычно для пикового auxiliary-использования). Не забывайте про стек рекурсии, уточняйте, включаются ли вход и выход, и указывайте, для какого случая дана оценка."}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Создание нового массива чаще всего добавляет линейные затраты: O(n) по времени из‑за копирования элементов и O(n) по памяти под новый буфер. Пустой массив создать можно за O(1), но как только вы копируете или заполняете его данными, появляется линейная стоимость. Частое создание новых массивов внутри циклов и рекурсии может превращать изначально линейный алгоритм в квадратичный из‑за многократных копирований."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Подробный разбор"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Что значит «создать новый массив»:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Пустой массив или с предзаданной длиной: создание оболочки обычно O(1); заполнение n элементов — O(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Копия существующего массива: O(n) время и O(n) доп. память (копирование ссылок/значений — чаще всего поверхностное копирование)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Операции, возвращающие новый массив (map, filter, slice, concat, оператор spread): обычно O(n) по времени и O(n) по памяти; для concat двух массивов длиной n и m — O(n + m)."}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Влияние на временную сложность алгоритма:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Один раз скопировать массив — это дополнительный линейный шаг (O(n))."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Если копирование происходит на каждой итерации цикла или каждого уровня рекурсии, суммарная сложность может вырасти до O(n²) из‑за многократного копирования всё более длинных массивов."}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Влияние на пространственную сложность:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Новый массив требует O(n) дополнительной памяти."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Композиции вроде filter().map() создают промежуточные массивы, увеличивая пиковое потребление памяти."}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Реалокации и амортизация:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Добавление в конец исходного массива обычно амортизированно O(1) благодаря запасу ёмкости."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Если же вы каждый раз создаёте новый массив (например, через concat), амортизационные преимущества теряются: происходит копирование всех элементов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Предварительное выделение длины помогает избежать многократных расширений."}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"GC и кэш-память:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Много временных массивов усиливают давление на сборщик мусора."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Копирование больших блоков данных ухудшает локальность и может приводить к кэш‑миссам на уровне CPU."}]}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Иммутабельность и функциональный стиль:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"В иммутабельном стиле новые массивы — нормальная цена за предсказуемость и отсутствие побочных эффектов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Обычные массивы в JavaScript не используют структурного шаринга, поэтому копирование стоит O(n). Персистентные структуры данных сглаживают эту цену, но это уже другие структуры."}]}]}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Примеры и сравнения"}]},{"type":"paragraph","content":[{"type":"text","text":"Копирование и конкатенация: время и память."}]},{"type":"codeBlock","content":[{"type":"text","text":"const n = 100000;
const a = Array.from({ length: n }, (_, i) => i);

// O(n): копия
const b = a.slice();

// O(n): копия
const c = [...a];

// O(n + m): копия обоих массивов
const d = a.concat(c);

// O(n) время, O(n) дополнительная память из-за промежуточного массива после filter
const res = a.filter(x => x % 2 === 0).map(x => x * 2);"}]},{"type":"paragraph","content":[{"type":"text","text":"Иммутабельное наращивание через concat в цикле приводит к квадратичной сложности."}]},{"type":"codeBlock","content":[{"type":"text","text":"const n = 100000;
const items = Array.from({ length: n }, (_, i) => i);

// Плохо: O(n^2) из-за копирования массива на каждом шаге
let out = [];
for (const x of items) {
  out = out.concat([x]); // каждый concat копирует out целиком
}

// Хорошо: O(n) амортизированно
let out2 = [];
for (const x of items) {
  out2.push(x); // амортизированно O(1) на шаг
}"}]},{"type":"paragraph","content":[{"type":"text","text":"Удаление элемента: in-place против создания нового массива."}]},{"type":"codeBlock","content":[{"type":"text","text":"const a = [1, 2, 3, 4, 5];
const target = 3;

// In-place: O(n) время (сдвиг), O(1) доп. память
const i = a.indexOf(target);
if (i !== -1) a.splice(i, 1);

// Иммутабельно: O(n) время, O(n) память (новый массив)
const a2 = a.filter(x => x !== target);"}]},{"type":"paragraph","content":[{"type":"text","text":"Копирование в рекурсии: как линейное превращается в квадратичное."}]},{"type":"codeBlock","content":[{"type":"text","text":"// Плохо: на каждом шаге создаётся новый массив за счет concat => суммарно O(n^2)
function recBuild(n, acc = []) {
  if (n === 0) return acc;
  return recBuild(n - 1, acc.concat(n));
}

// Лучше: мутируем аккумулятор (если это допустимо) => O(n)
function recBuildBetter(n, acc = []) {
  if (n === 0) return acc;
  acc.push(n);
  return recBuildBetter(n - 1, acc);
}"}]},{"type":"paragraph","content":[{"type":"text","text":"Предварительное выделение и заполнение без лишних копий."}]},{"type":"codeBlock","content":[{"type":"text","text":"const n = 100000;
const arr = new Array(n); // выделяем длину
for (let i = 0; i < n; i++) {
  arr[i] = i * 2; // O(n) без промежуточных массивов
}

// Альтернатива без промежуточных копий: один проход вместо filter().map()
const src = Array.from({ length: n }, (_, i) => i);
const doubledEvens = [];
for (let i = 0; i < src.length; i++) {
  const x = src[i];
  if ((x & 1) === 0) doubledEvens.push(x * 2);
}"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Когда создание новых массивов оправдано"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Иммутабельные обновления состояния в UI: предсказуемость и простое определение изменений."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Чистые функции и тестируемость: отсутствие побочных эффектов важнее небольших накладных расходов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Снапшоты, откаты, история изменений: нужен независимый слепок данных."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Параллельная/асинхронная обработка: чтобы исключить гонки при модификации общего состояния."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Объём мал или операция редкая, а читаемость кода важнее микрооптимизаций."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Практические рекомендации"}]},{"type":"orderedList","attrs":{"order":1},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не копируйте массив на каждом шаге цикла; используйте push, аккумуляторы и предварительное выделение длины."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Избегайте arr = arr.concat(x) в горячих участках; предпочтительнее push или push с операторами распространения, если это один массив."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Склеивайте несколько проходов в один, если важны ресурсы: вместо filter().map() — один цикл или reduce."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Профилируйте для больших n: проверяйте время, пиковую память и активность сборщика мусора."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Если нужна иммутабельность, рассмотрите персистентные структуры данных со структурным разделением, чтобы снизить цену копирования."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Помните: spread и slice — это копии O(n), используйте их осознанно."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Частые вставки/удаления в середине массива всё равно стоят O(n) по времени; для таких паттернов подумайте о других структурах или об изменении подхода."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Итоги"}]},{"type":"paragraph","content":[{"type":"text","text":"Создание новых массивов — это, как правило, линейные затраты по времени и памяти. Одноразовая копия — нормально, но регулярное копирование в циклах и рекурсии быстро накапливает цену и может превратить алгоритм в квадратичный. Выбирайте между иммутабельностью и производительностью осознанно: где важна скорость — предпочитайте один проход, in-place операции и предварительное распределение; где важна предсказуемость — иммутабельные подходы, но без лишних копий."}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Стек вызовов — это область памяти процесса, где послойно (по принципу LIFO) хранятся кадры (frames) активных функций: адрес возврата, аргументы, локальные переменные и сохранённые регистры. Он очень быстрый, управляется автоматически при входе/выходе из функций, имеет ограниченный размер и создаётся отдельно для каждого потока. Переполнение стека происходит при слишком глубокой рекурсии или слишком больших локальных данных."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Подробный разбор"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Что хранится в стеке"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Кадры вызовов (stack frames) — один кадр на активную функцию."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Адрес возврата — куда продолжать выполнение после return."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Аргументы функции и её локальные переменные (которые не «убегают» за пределы функции)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сохранённые регистры и указатель кадра (FP) — для восстановления контекста."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Принцип LIFO: последний вызванный — первый завершённый."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Автоматическое время жизни: память выделяется/освобождается при входе/выходе из функции."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ограниченный размер (обычно мегабайты), высокая скорость доступа и отсутствует явный GC для стека."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"У каждого потока — свой стек; используются SP (stack pointer) и часто FP (frame/base pointer)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Стек vs куча (heap)"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Стек: быстрый, LIFO, автоматический, ограниченный, локальные данные и аргументы, кадры функций, не требует явного освобождения."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Куча: гибкая, произвольный порядок жизни объектов, больше размер, выделение/освобождение дороже; управляется вручную (C/C++) или GC (JS, Java)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как происходит вызов и возврат"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Передача аргументов вызываемой функции (через стек/регистры, зависит от ABI)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сохранение адреса возврата и необходимых регистров, сдвиг указателя стека (SP) — «выталкивание» кадра."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Выполнение тела функции, работа с локальными переменными."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"При return: восстановление регистров, сворачивание кадра (SP возвращается), переход по адресу возврата."}]}]}]},{"type":"codeBlock","content":[{"type":"text","text":"+----------------------------+  высокие адреса
| frame: main                |
| locals, args               |
| return addr -> runtime     |
+----------------------------+
| frame: g()                 |
| saved FP, locals, args     |
| return addr -> main        |
+----------------------------+
| frame: f()                 |
| saved FP, locals, args     |
| return addr -> g           |
+----------------------------+  низкие адреса
            ^
            SP (stack pointer)  — указывает на вершину стека
            FP (frame pointer)  — указывает на базу текущего кадра"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Примеры"}]},{"type":"heading","attrs":{"level":4},"content":[{"type":"text","text":"C: локальные переменные, рекурсия и переполнение стека"}]},{"type":"codeBlock","content":[{"type":"text","text":"#include <stdio.h>

int f(int n) {
    int local = n;                 // локальная переменная в стеке
    if (n == 0) return local;
    return f(n - 1) + 1;           // каждый вызов создаёт новый кадр
}

int main() {
    // Крупный объект на стеке — риск переполнения (не делайте так)
    // int big[10 * 1024 * 1024];  // ~40 МБ на 64-бит — вероятный crash

    // Глубокая рекурсия тоже может переполнить стек
    printf("%d\n", f(1000000));   // в какой-то момент упадёт (stack overflow)
    return 0;
}

// ВАЖНО: нельзя возвращать адрес локальной переменной
// int* bad() {
//     int x = 42;   // x живёт только пока кадр функции на стеке
//     return &x;    // НЕПРАВИЛЬНО: после return кадр уничтожен
// }"}]},{"type":"paragraph","content":[{"type":"text","text":"В C локальные переменные живут до выхода из функции. Большие локальные массивы или глубокая рекурсия легко ведут к переполнению стека. Для больших буферов используйте кучу (malloc/new)."}]},{"type":"heading","attrs":{"level":4},"content":[{"type":"text","text":"JavaScript: стек вызовов и асинхронность"}]},{"type":"codeBlock","content":[{"type":"text","text":"// Синхронный стек и трассировка
function a() { b(); }
function b() { c(); }
function c() {
  // В большинстве JS-движков Error().stack показывает текущий стек
  console.log(String(new Error().stack));
}
a();

// Асинхронность: колбэки не продолжают текущий стек
console.log('start');
setTimeout(() => console.log('timeout callback (новый стек)'), 0);
Promise.resolve().then(() => console.log('microtask (после текущего стека)'));
console.log('end');

// Переполнение стека в JS
function recurse(i) { return recurse(i + 1); }
try {
  recurse(0);
} catch (e) {
  console.error(e.name + ': ' + e.message); // RangeError: Maximum call stack size exceeded
}"}]},{"type":"paragraph","content":[{"type":"text","text":"В JS стек управляется движком: каждый синхронный вызов добавляет кадр, return снимает. Асинхронные колбэки выполняются позже, когда текущий стек пуст — это уже новый стек, поэтому «продолжения» стека у них нет. Ошибка переполнения возникает при слишком глубокой (часто бесконечной) рекурсии."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Исключения и «разворачивание стека»"}]},{"type":"paragraph","content":[{"type":"text","text":"При выбросе исключения (например, throw) выполненные, но незавершённые кадры последовательно снимаются до обработчика (catch) — это называется разворачивание стека. На каждом шаге выполняются финализаторы: finally-блоки (JS), деструкторы (C++/Rust drop). Если обработчик не найден, программа завершается с ошибкой и печатает трассировку стека."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Многопоточность и веб"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Каждый поток ОС имеет свой собственный стек с фиксированным начальным размером (часто 1–8 МБ), который может расти до лимита."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"В браузере основной поток UI и каждый Web Worker имеют свой стек. Колбэки событий/таймеров выполняются на «пустом» стеке, когда цикл событий готов их обработать."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Асинхронные границы (таймеры, I/O, промисы) разрывают непрерывность стека: «дальше» код идёт уже в новом кадре и часто с новой трассировкой."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Оптимизации и нюансы"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Tail-call optimization (TCO): теоретически позволяет не наращивать стек при хвостовой рекурсии, но в JS она редко реализована на практике."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Inlining и опускание указателя кадра: компиляторы/движки могут убирать кадры или объединять их, что влияет на трассировки стека в дебаге."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Escape analysis: если объект «не убегает» за пределы функции, некоторые языки/компиляторы размещают его на стеке (Go, в оптимизациях JIT). В JS замыкания обычно уводят данные в кучу."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Безопасность: защитные страницы и canary-значения помогают детектировать переполнения стека на уровне ОС/рантайма."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Практические рекомендации"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Избегайте глубокой/бесконечной рекурсии в JS: предпочитайте итерацию или переписывайте на хвостовую рекурсию только если TCO гарантируется (обычно нет)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не размещайте большие объёмы данных на стеке; используйте кучу для массивов/буферов значительного размера."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Понимайте границы стека при асинхронности: ошибки и трассировки часто «обрываются» на границе await/then; добавляйте контекст вручную при необходимости."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Используйте трассировки стека в логах для диагностики; в браузере и Node.js ориентируйтесь на Error.stack и карты исходников."}]}]}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Рекурсия повышает пространственную сложность из‑за дополнительного стека вызовов: каждая активация функции занимает память под локальные переменные и адрес возврата. Обычно это O(h), где h — глубина рекурсии. Для линейной рекурсии h=O(n), для двоичной — h равно высоте рекурсивного дерева (часто O(log n) в алгоритмах «разделяй и властвуй»). Без оптимизации хвостовой рекурсии память не освобождается до свёртки вызовов; при TCO хвостовая рекурсия может иметь O(1) стек."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Подробное объяснение"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как формируется пространственная сложность при рекурсии"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Стек вызовов: каждый рекурсивный вызов создаёт фрейм со своими локальными данными."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Глубина рекурсии h: максимальное число одновременно «живых» вызовов определяет дополнительную память O(h)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дополнительные структуры: помимо стека, алгоритм может использовать массивы/кэши, что добавляет память к общей оценке."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Базовый пример: линейная рекурсия vs итерация"}]},{"type":"paragraph","content":[{"type":"text","text":"Факториал: рекурсивное решение использует O(n) стека, итеративное — O(1)."}]},{"type":"codeBlock","content":[{"type":"text","text":"// JavaScript
function factRec(n) {
  if (n <= 1) return 1;      // глубина стека: n
  return n * factRec(n - 1); // пространственная сложность по стеку: O(n)
}

function factIter(n) {
  let res = 1;               // O(1) дополнительной памяти
  for (let i = 2; i <= n; i++) res *= i;
  return res;
}"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Двоичная рекурсия: глубина vs количество вызовов"}]},{"type":"paragraph","content":[{"type":"text","text":"Наивный Fibonacci делает экспоненциально много вызовов, но глубина стека остаётся O(n). Пространственная сложность по стеку определяется именно глубиной, а не числом всех вызовов."}]},{"type":"codeBlock","content":[{"type":"text","text":"// JavaScript
function fib(n) {
  if (n <= 1) return n;      // глубина стека: n
  return fib(n - 1) + fib(n - 2); // количество вызовов экспоненциально, но стек: O(n)
}"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Разделяй и властвуй: типичные оценки"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Quicksort: средняя глубина рекурсии O(log n) → стек O(log n); худший случай — O(n). Дополнительных структур нет (кроме стека), если сортируем на месте."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Mergesort (топ-даун): стек O(log n) по глубине, но требуется дополнительный вспомогательный массив O(n), что доминирует."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Бинарный поиск: рекурсивная глубина O(log n) → стек O(log n). Итеративная версия — O(1)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Деревья/графы: DFS рекурсивно и итеративно"}]},{"type":"paragraph","content":[{"type":"text","text":"Рекурсивный DFS использует стек вызовов O(h), где h — высота дерева/длина пути; итеративный вариант использует явный стек той же асимптотики, но контролируемый в куче."}]},{"type":"codeBlock","content":[{"type":"text","text":"// JavaScript: DFS по дереву
function dfsRec(node) {
  if (!node) return; // стек: O(h)
  process(node);
  for (const child of node.children) dfsRec(child);
}

function dfsIter(root) {
  const stack = [root];      // явный стек: O(h)
  while (stack.length) {
    const node = stack.pop();
    if (!node) continue;
    process(node);
    // чтобы порядок совпадал с рекурсией, добавляем детей в обратном порядке
    for (let i = node.children.length - 1; i >= 0; i--) {
      stack.push(node.children[i]);
    }
  }
}"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Хвостовая рекурсия и TCO"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Без оптимизации хвостовой рекурсии (TCO) даже хвостовые вызовы накапливают стек → O(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"При включённой TCO компилятор переиспользует один фрейм → стек O(1)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Поддержка TCO зависит от языка/компилятора/флагов; во многих средах web-разработки (например, типичный JS рантайм) TCO не гарантируется."}]}]}]},{"type":"codeBlock","content":[{"type":"text","text":"// Хвостовая рекурсия (теоретически TCO → O(1), иначе O(n))
function sumRecTail(arr, i = 0, acc = 0) {
  if (i === arr.length) return acc; // хвостовой вызов
  return sumRecTail(arr, i + 1, acc + arr[i]);
}

// Эквивалентная итерация — всегда O(1)
function sumIter(arr) {
  let acc = 0;
  for (let i = 0; i < arr.length; i++) acc += arr[i];
  return acc;
}"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Учёт дополнительной памяти (кэши, буферы)"}]},{"type":"paragraph","content":[{"type":"text","text":"Если рекурсия использует мемоизацию или временные буферы, общая пространственная сложность — сумма: стек O(h) плюс память под кэш/буфер. Например, динамическое программирование по массиву с мемоизацией даёт O(n) памяти сверх стека."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Практические выводы для собеседования"}]},{"type":"orderedList","attrs":{"start":1},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Определяйте максимальную глубину рекурсии h — именно она задаёт потребление стека."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Учитывайте вспомогательные структуры данных: они могут доминировать (как в mergesort)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сравнивайте с итерацией: рекурсию часто можно переписать на цикл с явным стеком/очередью, сохранив асимптотику по времени и контролируя память."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Оценивайте худший случай: у quicksort стек может вырасти до O(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Знайте про TCO, но не полагайтесь на неё, если среда не гарантирует оптимизацию."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Итог"}]},{"type":"paragraph","content":[{"type":"text","text":"Рекурсия добавляет к пространственной сложности расход стека O(h), где h — максимальная глубина рекурсивных вызовов. В одних задачах это O(n), в других — O(log n); в худших случаях возможно O(n) и переполнение стека. Итеративные версии и оптимизации (TCO, хвостовая рекурсия, явные структуры) помогают удерживать память под контролем."}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Глубина рекурсии — это количество одновременно активных рекурсивных вызовов (глубина стека вызовов) в процессе выполнения алгоритма; также часто под ней понимают максимально возможную или фактическую максимальную глубину таких вызовов для конкретного входа. От глубины рекурсии напрямую зависит потребление стека (память) и риск переполнения стека."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Подробный ответ"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Определение"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Текущая глубина рекурсии: сколько кадров (frames) рекурсивной функции одновременно находится в стеке в данный момент выполнения."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Максимальная глубина рекурсии: наибольшее значение текущей глубины за время работы алгоритма на данном входе. Её часто используют для оценки расхода памяти и надёжности решения."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Почему это важно"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Стек памяти: каждый рекурсивный вызов держит локальные переменные и адрес возврата. Память по стеку растёт пропорционально глубине: O(depth)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Переполнение стека: если глубина превысит лимит среды/языка, программа упадёт с ошибкой переполнения стека."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Асимптотика: глубина рекурсии часто равна естественной мере задачи (размер входа, высота дерева, log n и т. д.) и определяет пространственную сложность."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Примеры"}]},{"type":"paragraph","content":[{"type":"text","text":"Пример 1: факториал с измерением максимальной глубины в JavaScript."}]},{"type":"codeBlock","content":[{"type":"text","text":"function fact(n, depth = 1, stats = { maxDepth: 0 }) {
  stats.maxDepth = Math.max(stats.maxDepth, depth);
  if (n <= 1) return 1;
  return n * fact(n - 1, depth + 1, stats);
}

const stats = { maxDepth: 0 };
console.log(fact(5, 1, stats)); // 120
console.log('maxDepth =', stats.maxDepth); // 5
// Максимальная глубина для fact(n) равна n (линейная рекурсия)."}]},{"type":"paragraph","content":[{"type":"text","text":"Пример 2: вычисление высоты (максимальной глубины) N-арного дерева в Python — глубина рекурсии равна высоте дерева."}]},{"type":"codeBlock","content":[{"type":"text","text":"class Node:
    def __init__(self, val, children=None):
        self.val = val
        self.children = children or []

def max_depth(root, depth=1):
    if root is None:
        return 0
    if not root.children:
        return depth
    return max(max_depth(c, depth + 1) for c in root.children)

root = Node(1, [Node(2), Node(3, [Node(4)])])
print(max_depth(root))  # 3
# Глубина рекурсии при обходе дерева = высоте дерева."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Оценка глубины рекурсии для типичных задач"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Линейная рекурсия (факториал, подсчёт суммы 1..n): глубина = n → O(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Бинарный поиск: глубина ≈ ⌊log2 n⌋ → O(log n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Обход дерева (DFS): глубина = высота дерева h → O(h). Для несбалансированного дерева h может быть O(n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Быстрая сортировка: средняя глубина = O(log n), в худшем случае = O(n) (при плохом выборе опорного элемента)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Глубина рекурсии и сложность по памяти"}]},{"type":"paragraph","content":[{"type":"text","text":"Пространственная сложность рекурсивного алгоритма обычно равна O(depth), т. к. одновременно в стеке находится глубина кадров вызова. Приблизительное потребление памяти можно оценить как: память ≈ размер_кадра × depth."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Размер кадра включает локальные переменные, параметры, адрес возврата и службу рантайма."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Хвостовая рекурсия при наличии оптимизации может удерживать O(1) стека, т. к. кадр переиспользуется."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Хвостовая рекурсия и оптимизация"}]},{"type":"paragraph","content":[{"type":"text","text":"Хвостовой вызов — это рекурсивный вызов, оказывающийся последней операцией функции. При поддержке оптимизации хвостовых вызовов (TCO) глубина рекурсии логически может быть большой, но физически стек остаётся O(1). Однако во многих популярных средах TCO либо недоступна, либо не гарантируется."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Надёжный подход для глубокой рекурсии: переписать в итеративный алгоритм с явным стеком/циклом."}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Сравнение хвостовой и итеративной версии на примере суммы 1..n в JavaScript."}]},{"type":"codeBlock","content":[{"type":"text","text":"function sumRange(n, acc = 0) {
  if (n === 0) return acc; // хвостовой вызов
  return sumRange(n - 1, acc + n);
}

// Итеративно (надежнее для больших n):
function sumRangeIter(n) {
  let acc = 0;
  while (n > 0) {
    acc += n;
    n--;
  }
  return acc;
}

console.log(sumRange(5));     // 15
console.log(sumRangeIter(5)); // 15"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Ограничения и практические советы"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Контролируйте базовый случай. Он должен гарантированно срабатывать и уменьшать глубину; иначе возможна бесконечная рекурсия."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Оценивайте худшую глубину на реальных данных: для несбалансированных структур она может быть линейной."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Настройка/лимиты: в одних средах можно менять лимит рекурсии или размер стека (например, в некоторых языках/Рuntimes), в других — нельзя; учитывайте ограничения целевой платформы."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Для потенциально большой глубины используйте итеративные решения или собственный стек/очередь."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не полагайтесь на TCO там, где она не гарантируется; рассчитывайте на O(depth) по памяти."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как отвечать на собеседовании"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дать определение: глубина рекурсии — число активных рекурсивных вызовов и/или максимально достигнутая глубина."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Упомянуть связь со стеком и пространственной сложностью O(depth)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Привести пример (факториал/DFS) и сказать, от чего зависит глубина (n, высота дерева, log n)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Описать риски переполнения стека и альтернативы (итерация, собственный стек, балансировка, хвостовая рекурсия)."}]}]}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Как избежать переполнения стека рекурсией"}]},{"type":"paragraph","content":[{"type":"text","text":"Короткий ответ:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Замените глубокую рекурсию на итерацию с явным стеком/очередью."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Используйте хвостовую рекурсию только там, где язык реально оптимизирует TCO; иначе применяйте трамплин."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Перепишите топ-даун на bottom-up (динамическое программирование) без рекурсии."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Разбивайте работу на порции и отдавайте управление циклу событий при больших объёмах (асинхронная итерация)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Вводите порог глубины/фоллбэк и валидируйте базовый случай."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Почему возникает переполнение стека"}]},{"type":"paragraph","content":[{"type":"text","text":"Каждый рекурсивный вызов занимает кадр стека. При глубокой рекурсии (линейные структуры, несбалансированные деревья, очень большие n) стек переполняется. Даже с корректным базовым случаем глубина может превысить лимит рантайма."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Практические стратегии"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"1) Заменить рекурсию на итерацию (явный стек/очередь)"}]},{"type":"paragraph","content":[{"type":"text","text":"Итерация не растит системный стек: вы контролируете глубину через свою структуру данных. Это универсальный и надёжный подход для обходов деревьев/графов, поиска, сортировок и т. д."}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"// DFS по бинарному дереву без рекурсии
class Node { constructor(val, left = null, right = null) { this.val = val; this.left = left; this.right = right; } }

function dfsIter(root) {
  if (!root) return [];
  const res = [];
  const stack = [root];
  while (stack.length) {
    const node = stack.pop();
    res.push(node.val);
    if (node.right) stack.push(node.right);
    if (node.left) stack.push(node.left);
  }
  return res;
}
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"2) Хвостовая рекурсия и трамплин"}]},{"type":"paragraph","content":[{"type":"text","text":"Хвостовая рекурсия безопасна только если язык/компилятор гарантирует TCO (tail call optimization). Во многих средах JavaScript TCO отсутствует, поэтому используйте трамплин — он разворачивает рекурсивные шаги в цикл."}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"// Трамплин для эмуляции TCO
const trampoline = (fn) => (...args) => {
  let result = fn(...args);
  while (typeof result === 'function') {
    result = result();
  }
  return result;
};

// Хвостовая версия factorial на BigInt + трамплин
const factStep = (n, acc = 1n) => (n <= 1n ? acc : () => factStep(n - 1n, acc * n));
const factorial = trampoline(factStep);

console.log(String(factorial(10000n)).length); // работает без переполнения стека
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"3) Bottom-up динамическое программирование"}]},{"type":"paragraph","content":[{"type":"text","text":"Перепишите мемоизируемую рекурсивную задачу в итеративную bottom-up форму. Это убирает стек вызовов и часто быстрее."}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"// Fibonacci: bottom-up вместо рекурсии
function fib(n) {
  if (n <= 1) return n;
  let a = 0, b = 1;
  for (let i = 2; i <= n; i++) {
    [a, b] = [b, a + b];
  }
  return b;
}
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"4) Разбиение на порции и асинхронная обработка"}]},{"type":"paragraph","content":[{"type":"text","text":"При большом объёме работы используйте итеративный алгоритм и периодически «уступайте» управление циклу событий, чтобы не блокировать поток и держать память под контролем."}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"// Итеративный обход с уступкой циклу событий
async function traverseLargeTree(root, yieldEvery = 1000) {
  const stack = root ? [root] : [];
  let steps = 0;
  while (stack.length) {
    const node = stack.pop();
    // ... обработка node
    if (node.right) stack.push(node.right);
    if (node.left) stack.push(node.left);
    if (++steps % yieldEvery === 0) {
      await Promise.resolve(); // microtask yield
    }
  }
}
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"5) Порог глубины/фоллбэк и валидация"}]},{"type":"paragraph","content":[{"type":"text","text":"Иногда полезно ограничить глубину и переключиться на альтернативный алгоритм (или бросить контролируемую ошибку). Также убедитесь, что базовый случай достижим и вход уменьшается."}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"// Пример защитного лимита глубины
function safeDFS(node, maxDepth = 1000, depth = 0) {
  if (!node) return;
  if (depth > maxDepth) throw new Error('Depth limit exceeded');
  // ... обработка node
  safeDFS(node.left, maxDepth, depth + 1);
  safeDFS(node.right, maxDepth, depth + 1);
}
"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Валидация базовых условий"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Базовый случай обязателен и достижим."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Аргументы рекурсивного вызова монотонно «приближаются» к базовому случаю."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Нет циклических зависимостей/петель без посещённого множества."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Частые ошибки"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Расчёт на хвостовую оптимизацию там, где рантайм её не поддерживает."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Рекурсивный обход несбалансированных деревьев (вниз в одну ветку) — гарантированный риск переполнения."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Мемоизация без контроля глубины: уменьшает число вызовов, но не максимальную глубину стека."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Краткий чек-лист на собеседовании"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Оцените максимальную глубину рекурсии на худшем кейсе."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Предложите итеративную альтернативу с явным стеком/очередью."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Если предлагаете хвостовую рекурсию — уточните поддержку TCO и/или покажите трамплин."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Для задач из класса DP — перепишите в bottom-up."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"При больших объёмах — порционирование и async/yield."}]}]}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Сортировка пузырьком имеет временную сложность: лучший случай O(n) (с оптимизацией раннего выхода), средний и худший — O(n^2). Пространственная сложность O(1), алгоритм устойчивый и выполняется на месте."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Подробный разбор"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Временная сложность"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Лучший случай: O(n), если используется флаг «были ли обмены» и массив уже отсортирован (алгоритм завершится после одного прохода)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Средний случай: O(n^2) — при произвольных данных требуется порядка n·(n−1)/2 сравнений."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Худший случай: O(n^2) — для полностью обратной сортировки количество сравнений и обменов максимальное."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пространственная сложность"}]},{"type":"paragraph","content":[{"type":"text","text":"O(1) — сортировка выполняется на месте и требует только константной дополнительной памяти (переменные цикла и флаг обмена)."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Стабильность и адаптивность"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Устойчивый: равные элементы сохраняют относительный порядок."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Адаптивный (при оптимизации): если массив почти отсортирован, завершается быстрее, вплоть до O(n)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Сколько сравнений и обменов"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сравнения в худшем (и среднем) случае: n·(n−1)/2."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Обмены в худшем случае: n·(n−1)/2; в лучшем — 0 (если используем ранний выход)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Без флага раннего выхода даже в отсортированном массиве будет выполнено ~n·(n−1)/2 сравнений."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Оптимизации"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Флаг swapped: если за проход не было обменов — массив отсортирован, выходим (даёт лучший случай O(n))."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Сокращение границы: после каждого прохода последний элемент на своём месте — уменьшаем длину внутреннего цикла."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Запоминание позиции последнего обмена: позволяет ещё сильнее уменьшать диапазон следующего прохода."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Двунаправленный (cocktail) пузырёк: гоняет крупные элементы вправо и мелкие влево за один цикл, ускоряя работу на некоторых данных."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Когда использовать и когда нет"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Использовать: для учебных целей, очень маленьких массивов, почти отсортированных данных, когда важна простота реализации и устойчивость."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Не использовать: для средних и больших массивов в продакшене — есть алгоритмы O(n log n), работающие быстрее (quicksort, mergesort, heapsort)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример: оптимизированная сортировка пузырьком (JavaScript, ES6)"}]},{"type":"codeBlock","content":[{"type":"text","text":"function bubbleSort(arr) {
  const a = arr.slice(); // не мутируем исходный массив
  let n = a.length;
  let swapped;
  do {
    swapped = false;
    for (let i = 1; i < n; i++) {
      if (a[i - 1] > a[i]) {
        [a[i - 1], a[i]] = [a[i], a[i - 1]]; // обмен
        swapped = true;
      }
    }
    n--; // последний элемент уже на месте
  } while (swapped);
  return a;
}

console.log(bubbleSort([5, 1, 4, 2, 8])); // [1, 2, 4, 5, 8]"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример: двунаправленная (cocktail) сортировка пузырьком"}]},{"type":"codeBlock","content":[{"type":"text","text":"function cocktailSort(arr) {
  const a = arr.slice();
  let left = 0;
  let right = a.length - 1;
  let swapped = true;

  while (swapped) {
    swapped = false;
    // проход слева направо
    for (let i = left; i < right; i++) {
      if (a[i] > a[i + 1]) {
        [a[i], a[i + 1]] = [a[i + 1], a[i]];
        swapped = true;
      }
    }
    right--;
    if (!swapped) break;

    swapped = false;
    // проход справа налево
    for (let i = right; i > left; i--) {
      if (a[i - 1] > a[i]) {
        [a[i - 1], a[i]] = [a[i], a[i - 1]];
        swapped = true;
      }
    }
    left++;
  }
  return a;
}

console.log(cocktailSort([3, 0, 2, 5, -1, 4, 1])); // [-1, 0, 1, 2, 3, 4, 5]"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Сравнение с другими алгоритмами"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Insertion sort: тоже O(n^2), но обычно быстрее пузырька на практике; лучший случай O(n) без доп. памяти, устойчивый."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Selection sort: O(n^2), минимум обменов (O(n)), но неустойчивый; часто быстрее пузырька по числу записей в память."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Quicksort / Mergesort / Heapsort: асимптотически быстрее на больших n — O(n log n), предпочтительны для продакшена."}]}]}]}]}

{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Время: O(log n) в среднем и худшем случаях; O(1) в лучшем (если искомый элемент — сразу в середине)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: O(1) для итеративной реализации; O(log n) для рекурсивной (за счёт стека вызовов)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Число сравнений: примерно ⌈log2 n⌉ (в пределах ⌈log2 n⌉…⌈log2 n⌉+1)."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Подробный разбор"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Предпосылки применения"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Данные отсортированы по ключу сравнения."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Есть случайный доступ к элементам за O(1) (например, массив/динамический массив)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Компаратор задаёт строгий порядок и транзитивен (без противоречий)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Почему O(log n)"}]},{"type":"paragraph","content":[{"type":"text","text":"На каждом шаге бинарный поиск делит текущий диапазон пополам и отбрасывает одну из половин. После k шагов остаётся не более n / 2^k элементов. Остановка происходит, когда осталось 1 или 0 элементов, то есть n / 2^k ≤ 1 ⇒ k ≥ ⌈log2 n⌉. Поэтому время — O(log n)."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Случаи по времени"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Лучший случай: O(1) — искомое значение сразу в середине."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Средний случай: O(log n) — усреднение по равномерному распределению целевого индекса."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Худший случай: O(log n) — требуется максимально возможное число шагов до сужения диапазона до единицы."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Память"}]},{"type":"paragraph","content":[{"type":"text","text":"Итеративная реализация использует константное количество переменных — O(1). Рекурсивная добавляет вложенность вызовов глубиной около ⌈log2 n⌉ — O(log n) по памяти."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Код (JavaScript)"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"// Итеративный бинарный поиск: индекс найденного элемента или -1
function binarySearch(arr, target) {
  let left = 0;
  let right = arr.length - 1;
  while (left <= right) {
    // Безопасное вычисление середины (защищает от переполнения в языках с 32-битными int)
    const mid = left + ((right - left) >> 1);
    if (arr[mid] === target) return mid;
    if (arr[mid] < target) left = mid + 1; else right = mid - 1;
  }
  return -1;
}

// lowerBound: первый индекс i, где arr[i] >= target
function lowerBound(arr, target) {
  let left = 0, right = arr.length; // полуинтервал [left, right)
  while (left < right) {
    const mid = left + ((right - left) >> 1);
    if (arr[mid] < target) left = mid + 1; else right = mid;
  }
  return left;
}

// upperBound: первый индекс i, где arr[i] > target
function upperBound(arr, target) {
  let left = 0, right = arr.length;
  while (left < right) {
    const mid = left + ((right - left) >> 1);
    if (arr[mid] <= target) left = mid + 1; else right = mid;
  }
  return left;
}

// Первый индекс вхождения target или -1 (для массивов с повторами)
function firstOccurrence(arr, target) {
  const i = lowerBound(arr, target);
  return i < arr.length && arr[i] === target ? i : -1;
}

// Последний индекс вхождения target или -1
function lastOccurrence(arr, target) {
  const j = upperBound(arr, target) - 1;
  return j >= 0 && arr[j] === target ? j : -1;
}

// Позиция вставки для поддержания сортировки (если элемента нет)
function insertionIndex(arr, target) {
  return lowerBound(arr, target);
}

// Примеры использования
const a = [1, 2, 4, 4, 5, 9, 12];
console.log(binarySearch(a, 5));        // 4
console.log(firstOccurrence(a, 4));     // 2
console.log(lastOccurrence(a, 4));      // 3
console.log(insertionIndex(a, 6));      // 5
"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Частые ошибки и нюансы"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Неправильные границы цикла: использовать согласованный полуинтервал [l, r) или замкнутый [l, r] и соответствующее условие остановки."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Расчёт середины как (l + r) / 2 может переполняться в языках с 32-битными целыми; безопаснее l + (r - l) / 2."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Зацикливание при неверном обновлении границ (например, r = mid вместо r = mid - 1 в замкнутом интервале)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Дубликаты: базовый поиск возвращает любой индекс найденного; для первого/последнего вхождения используйте lowerBound/upperBound."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Несортированные данные или структуры без O(1) доступа (например, связные списки) не подходят для классического бинарного поиска."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Сравнение с линейным поиском"}]},{"type":"paragraph","content":[{"type":"text","text":"Линейный поиск — O(n). Бинарный — O(log n). Например, при n = 1 000 000 бинарный поиск делает около 20 шагов, тогда как линейный может потребовать до миллиона сравнений."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Итог"}]},{"type":"paragraph","content":[{"type":"text","text":"Бинарный поиск работает за O(log n) по времени и O(1)/O(log n) по памяти (итеративно/рекурсивно). Это достигается благодаря поэтапному делению диапазона поиска пополам."}]}]}
